import{_ as a,a as t,b as s,c as i,d as n,e as o}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as l,o as d,c as r,a2 as p}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"IP Geolocation และ User Management","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/Other/ip-geolocation-and-user-management.md","filePath":"th-TH/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"th-TH/Other/ip-geolocation-and-user-management.md"};function u(h,e,g,m,b,P){return d(),r("div",null,[...e[0]||(e[0]=[p('<h1 id="ip-geolocation-และ-user-management" tabindex="-1">IP Geolocation และ User Management <a class="header-anchor" href="#ip-geolocation-และ-user-management" aria-label="Permalink to &quot;IP Geolocation และ User Management&quot;">​</a></h1><p>IP geolocation แปลง IP addresses ใน uploader records, login devices และ logs ที่คล้ายกันให้เป็น locations โดยประมาณ</p><p>หลัง configure แล้ว admin panel จะแสดงต้นทางของ upload และ access ได้ชัดขึ้น User Management ยังช่วย block หรือ restore upload access สำหรับ IP addresses ที่น่าสงสัยได้</p><h2 id="ตั้งค่าที่ไหน" tabindex="-1">ตั้งค่าที่ไหน <a class="header-anchor" href="#ตั้งค่าที่ไหน" aria-label="Permalink to &quot;ตั้งค่าที่ไหน&quot;">​</a></h2><p>เปิด:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+a+`" alt="IP geolocation" loading="lazy"></p><h2 id="available-settings" tabindex="-1">Available Settings <a class="header-anchor" href="#available-settings" aria-label="Permalink to &quot;Available Settings&quot;">​</a></h2><p>IP geolocation flow ใหม่รองรับหลาย sources ไม่ได้พึ่ง map service เดียว</p><table tabindex="0"><thead><tr><th>Setting</th><th>Purpose</th></tr></thead><tbody><tr><td>IP geolocation language</td><td>เลือก display language เช่น English, Simplified Chinese, Japanese, French และอื่น ๆ</td></tr><tr><td>MaxMind Account ID</td><td>MaxMind account ID สำหรับ MaxMind GeoLite Web Service</td></tr><tr><td>MaxMind License Key</td><td>MaxMind License Key</td></tr><tr><td>Tencent Map Key</td><td>Tencent Location Service key เหมาะกับ Chinese addresses และ mainland China IPs</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi key รองรับ multilingual IP geolocation</td></tr></tbody></table><p>กรอกเฉพาะ services ที่ต้องใช้ ไม่จำเป็นต้อง configure ทุก field</p><p>ถ้าไม่ใส่ key ImgBed ยังพยายามใช้ built-in free sources แต่ stability, language support และ precision อาจต่ำกว่า service ที่คุณ configure เอง</p><h2 id="recommended-choices" tabindex="-1">Recommended Choices <a class="header-anchor" href="#recommended-choices" aria-label="Permalink to &quot;Recommended Choices&quot;">​</a></h2><p>ถ้าต้องการ Chinese addresses เป็นหลัก:</p><ol><li>ตั้ง IP geolocation language เป็น Simplified Chinese</li><li>Configure Tencent Map Key</li><li>เพิ่ม MaxMind หรือ ipapi เป็น fallback ถ้าต้องการ</li></ol><p>ถ้าต้องการ English หรือ multilingual addresses:</p><ol><li>เลือก language ที่ต้องใช้</li><li>Configure MaxMind Account ID และ License Key</li><li>เพิ่ม ipapi Key ถ้าต้องการ multilingual results ที่ดีขึ้น</li></ol><h2 id="maxmind-setup" tabindex="-1">MaxMind Setup <a class="header-anchor" href="#maxmind-setup" aria-label="Permalink to &quot;MaxMind Setup&quot;">​</a></h2><p>MaxMind ต้องใช้:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>หา account ID ใน MaxMind dashboard และ generate License Key จาก License Keys page</p><p><img src="`+t+'" alt="MaxMind key config" loading="lazy"></p><p>หลัง generate แล้ว paste Account ID และ License Key ใน ImgBed แล้ว save</p><p>Free plan ของ MaxMind เหมาะกับ everyday use แต่มี request limits ถ้า quota เกิน ImgBed จะลอง sources อื่นที่ available ต่อ</p><h2 id="ipapi-setup" tabindex="-1">ipapi Setup <a class="header-anchor" href="#ipapi-setup" aria-label="Permalink to &quot;ipapi Setup&quot;">​</a></h2><p>ipapi ใช้ APILayer API Key</p><p>เปิด ipapi console แล้ว copy API Key ที่แสดง</p><p><img src="'+s+'" alt="ipapi config" loading="lazy"></p><p>Paste ใน field <code>ipapi Key</code> ใน ImgBed แล้ว save</p><p>ipapi รองรับ multilingual IP geolocation และมีประโยชน์เมื่ออยากแสดง addresses ใน selected language Free plan ก็มี request limits ถ้า quota หมด ImgBed จะลอง sources อื่นที่ available ต่อ</p><h2 id="tencent-map-key-setup" tabindex="-1">Tencent Map Key Setup <a class="header-anchor" href="#tencent-map-key-setup" aria-label="Permalink to &quot;Tencent Map Key Setup&quot;">​</a></h2><p>Tencent Map Key เหมาะกับ Chinese addresses โดยเฉพาะ mainland China IPs</p><p>ตอนสร้าง key ใน Tencent Location Service ให้ enable:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>หลังสร้างแล้ว paste key ใน <code>Tencent Map Key</code> แล้ว save</p><p>ถ้าต้องการ basic Chinese IP geolocation แค่ Tencent Map Key ก็เริ่มได้</p><h2 id="ควรดูอะไรใน-user-management" tabindex="-1">ควรดูอะไรใน User Management <a class="header-anchor" href="#ควรดูอะไรใน-user-management" aria-label="Permalink to &quot;ควรดูอะไรใน User Management&quot;">​</a></h2><p>User Management เปิดได้จากด้านบนของ admin panel</p><p><img src="'+i+'" alt="User management" loading="lazy"></p><p>User Management แสดง upload activity ตาม IP:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>IP source</td><td>Uploader source IP</td></tr><tr><td>Address</td><td>Location โดยประมาณที่ resolve จาก IP</td></tr><tr><td>Total upload size</td><td>Total file size ที่ upload จาก IP นี้</td></tr><tr><td>Upload count</td><td>จำนวน uploads จาก IP นี้</td></tr><tr><td>Upload allowed</td><td>On หมายถึง allow uploads Off หมายถึง block uploads</td></tr></tbody></table><p>คลิก arrow ทางซ้ายเพื่อ expand list ของ files ที่ upload โดย IP นั้น</p><p>File list แสดง file name, preview, file size, moderation result, file status และ upload time ถ้า uploads ดูน่าสงสัย ให้ expand IP ก่อน review files แล้วค่อยตัดสินใจว่าจะ block uploads ต่อไปหรือไม่</p><p>ถ้า IP น่าสงสัย ให้ปิด <code>Upload allowed</code> Future uploads จาก IP นั้นจะถูก block</p><h2 id="search-sort-และ-advanced-filters" tabindex="-1">Search, Sort และ Advanced Filters <a class="header-anchor" href="#search-sort-และ-advanced-filters" aria-label="Permalink to &quot;Search, Sort และ Advanced Filters&quot;">​</a></h2><p>ด้านบนของ User Management สามารถ search ด้วย IP source หรือ address</p><p>Sort ตาม time, upload count หรือ total upload size เพื่อหา recent uploaders, high-frequency uploaders หรือ high-usage IPs</p><p>ถ้าต้องการตรวจละเอียด ให้เปิด advanced filters</p><p><img src="'+n+'" alt="Advanced filters" loading="lazy"></p><p>Advanced filters รองรับ:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Usage</th></tr></thead><tbody><tr><td>Time range</td><td>แสดง IPs ที่ upload files ในช่วงเวลาที่เลือก</td></tr><tr><td>Access status</td><td>Filter ตาม normal, blocked และ states ที่คล้ายกัน</td></tr><tr><td>Allow/block list</td><td>Filter ตาม allowlist, blocklist หรือ unset</td></tr><tr><td>File type</td><td>แสดง IPs ที่ upload images, videos, audio, documents, code หรือ other files</td></tr><tr><td>File size</td><td>Filter ตาม uploaded file size range</td></tr><tr><td>Age rating</td><td>Filter ตาม unset, General, R12+, R16+, R18 และ ratings คล้ายกัน</td></tr><tr><td>File status</td><td>Filter ตาม current file status เพื่อตรวจ abnormal files</td></tr></tbody></table><p>คลิก <code>Apply Filters</code> เพื่อ apply ใช้ <code>Reset</code> เพื่อกลับไปดูข้อมูลทั้งหมด</p><h2 id="mobile-view" tabindex="-1">Mobile View <a class="header-anchor" href="#mobile-view" aria-label="Permalink to &quot;Mobile View&quot;">​</a></h2><p>บน mobile User Management จะเปลี่ยนเป็น card layout</p><p><img src="'+o+`" alt="Mobile user management" loading="lazy"></p><p>แต่ละ card แสดง IP, address, total upload size, upload count และ upload allowed switch จัดการ users ได้โดยไม่ต้อง scroll table แนวนอน</p><h2 id="ถ้า-location-ดูผิด" tabindex="-1">ถ้า Location ดูผิด <a class="header-anchor" href="#ถ้า-location-ดูผิด" aria-label="Permalink to &quot;ถ้า Location ดูผิด&quot;">​</a></h2><p>IP geolocation เป็นค่าโดยประมาณ ไม่ใช่ street address ที่แม่นยำ</p><p>ถ้า user อยู่หลัง proxy, data center, cloud server หรือ cross-border network location ที่แสดงอาจต่างจาก location จริง</p><p>ใช้ feature นี้เพื่อเข้าใจ rough origin, หา abnormal uploads และช่วยตัดสินใจ block อย่าใช้แทน precise tracking</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Address ว่าง</td><td>IP อาจยังไม่ resolve หรือ current source unavailable ชั่วคราว</td></tr><tr><td>Address language ผิด</td><td>ตรวจ IP geolocation language และมี source ที่รองรับ language นั้น configured หรือไม่</td></tr><tr><td>Address แสดง data center</td><td>Proxies, cloud servers และ crawlers จำนวนมากแสดงเป็น data center หรือ ISP addresses</td></tr><tr><td>Upload count สูง</td><td>Review IP นี้อย่างระมัดระวัง และ block uploads หากจำเป็น</td></tr><tr><td>Total upload size ใหญ่</td><td>Sort หรือ filter, expand IP แล้วตรวจ specific files</td></tr><tr><td>ต้อง restore หลัง block</td><td>เปิด <code>Upload allowed</code> กลับเป็น on</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>เปิด IP Geolocation ใน Other Settings</span></span>
<span class="line"><span>-&gt; เลือก IP geolocation language</span></span>
<span class="line"><span>-&gt; กรอก MaxMind, Tencent Map หรือ ipapi credentials ตามต้องการ</span></span>
<span class="line"><span>-&gt; Save settings</span></span>
<span class="line"><span>-&gt; เปิด User Management</span></span>
<span class="line"><span>-&gt; Review IP source, address, total upload size และ upload count</span></span>
<span class="line"><span>-&gt; ใช้ search, sort หรือ advanced filters หา IPs ผิดปกติ</span></span>
<span class="line"><span>-&gt; Allow หรือ block uploads ตามต้องการ</span></span></code></pre></div>`,64)])])}const I=l(c,[["render",u]]);export{v as __pageData,I as default};
